// Vista: Login.js
// Este componente representa la vista del formulario de login y registro.
// Maneja la entrada del usuario y llama al controlador useAuth.

import React, { useState } from "react";
import AuthService from "../models/AuthService";
import "../styles/ChineseStyle.css";

const Login = () => {
  // Estados locales para el formulario
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [isRegistering, setIsRegistering] = useState(false);
  const [userNotFoundEmail, setUserNotFoundEmail] = useState(null); // Para registrar si no existe

  // Manejador para el envío del formulario de login
  const handleLoginSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const result = await AuthService.loginWithEmail(email, password);
    setLoading(false);

    if (result.success) {
      console.log("Login exitoso");
      setEmail("");
      setPassword("");
      // El componente se re-renderizará cuando el user se actualice en App.js
    } else {
      // Si el usuario no existe, preguntar si quiere registrarse
      if (
        result.suggestion === "provider" &&
        (result.errorCode === "auth/user-not-found" ||
          result.errorCode === "auth/invalid-credential")
      ) {
        setUserNotFoundEmail(email);
        setError(
          `No existe una cuenta con ${email}. ¿Quieres registrarte ahora?`,
        );
      } else {
        setError(result.error);
      }
    }
  };

  // Manejador para el registro
  const handleRegisterSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Validar que el nombre no esté vacío
    if (!name.trim()) {
      setLoading(false);
      setError("El nombre es requerido");
      return;
    }

    try {
      console.log("Registrando usuario con:", { email, name });
      const result = await AuthService.registerWithEmail(
        email,
        password,
        name.trim(),
      );
      setLoading(false);

      if (result.success) {
        console.log("Registro exitoso");
        setIsRegistering(false);
        setUserNotFoundEmail(null);
        setEmail("");
        setPassword("");
        setName("");
        setError("Usuario registrado correctamente. ¡Bienvenido!");
        // Enviar email de bienvenida
        await AuthService.sendWelcomeEmail(email, email.split("@")[0]);
      } else {
        console.error("Error en registro:", result.error);
        setError(result.error);
      }
    } catch (err) {
      setLoading(false);
      console.error("Error capturado:", err);
      setError(err.message);
    }
  };

  // Manejador para registrarse cuando el usuario no existe
  const handleRegisterFromNotFound = async () => {
    if (!name.trim()) {
      setError("Ingresa tu nombre");
      return;
    }

    setLoading(true);
    setError(null);

    try {
      console.log("Registrando usuario no encontrado con:", {
        email: userNotFoundEmail,
        name,
      });
      const result = await AuthService.registerWithEmail(
        userNotFoundEmail,
        password,
        name.trim(),
      );
      setLoading(false);

      if (result.success) {
        console.log("Registro exitoso");
        setUserNotFoundEmail(null);
        setEmail("");
        setPassword("");
        setName("");
        setError("✅ Usuario creado correctamente. ¡Bienvenido!");
        // Enviar email de bienvenida
        await AuthService.sendWelcomeEmail(userNotFoundEmail, name);
      } else {
        console.error("Error en registro:", result.error);
        setError(result.error);
      }
    } catch (err) {
      setLoading(false);
      console.error("Error capturado:", err);
      setError(err.message);
    }
  };

  // Manejador para Google SignIn
  const handleGoogleSignIn = async () => {
    setLoading(true);
    setError(null);

    try {
      const result = await AuthService.loginWithGoogle();
      setLoading(false);

      if (result.success) {
        console.log("Google SignIn exitoso");
        // El componente se re-renderizará cuando el user se actualice en App.js
      } else {
        setError(result.error);
      }
    } catch (err) {
      setLoading(false);
      setError(err.message);
    }
  };

  // Manejador para login anónimo
  const handleAnonymousSignIn = async () => {
    setLoading(true);
    setError(null);

    try {
      const result = await AuthService.loginAnonymously();
      setLoading(false);

      if (result.success) {
        console.log("Login anónimo exitoso");
        // El componente se re-renderizará cuando el user se actualice en App.js
      } else {
        setError(result.error);
      }
    } catch (err) {
      setLoading(false);
      setError(err.message);
    }
  };

  return (
    <div className="login-container">
      <h2>{isRegistering ? "Registro" : "Iniciar Sesión"}</h2>

      {/* Formulario de login/registro normal */}
      {!isSmsLogin ? (
        <>
          {/* Si el usuario no fue encontrado, mostrar opción de registrarse */}
          {userNotFoundEmail ? (
            <div className="form-group-container">
              <div className="info-message">
                La cuenta con <strong>{userNotFoundEmail}</strong> no existe.
              </div>

              <form
                onSubmit={(e) => {
                  e.preventDefault();
                  handleRegisterFromNotFound();
                }}
              >
                <div className="form-group">
                  <label htmlFor="name">Tu nombre:</label>
                  <input
                    id="name"
                    type="text"
                    placeholder="¿Cuál es tu nombre?"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="password-new">Contraseña:</label>
                  <input
                    id="password-new"
                    type="password"
                    placeholder="Crea una contraseña"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="btn-primary"
                >
                  {loading ? "Creando cuenta..." : "Crear cuenta ahora"}
                </button>

                <button
                  type="button"
                  onClick={() => {
                    setUserNotFoundEmail(null);
                    setError(null);
                  }}
                  className="btn-secondary"
                >
                  Cancelar
                </button>
              </form>
            </div>
          ) : (
            <form
              onSubmit={
                isRegistering ? handleRegisterSubmit : handleLoginSubmit
              }
            >
              {isRegistering && (
                <div className="form-group">
                  <label htmlFor="name">Nombre:</label>
                  <input
                    id="name"
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
              )}

              <div className="form-group">
                <label htmlFor="email">Email:</label>
                <input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>

              <div className="form-group">
                <label htmlFor="password">Contraseña:</label>
                <input
                  id="password"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
              </div>

              <button type="submit" disabled={loading} className="btn-primary">
                {loading
                  ? "Cargando..."
                  : isRegistering
                    ? "Registrarse"
                    : "Iniciar Sesión"}
              </button>
            </form>
          )}
        </>
      ) : (
        /* Formulario de login con SMS */
        <form onSubmit={smsSent ? handleVerifySmsCode : handleSendSmsCode}>
          <div className="form-group">
            <label htmlFor="phone">Teléfono:</label>
            <input
              id="phone"
              type="tel"
              placeholder="612345678 (España) o +14155552671 (otro país)"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              disabled={smsSent}
              required
            />
            <small
              style={{
                color: "#666",
                fontSize: "12px",
                marginTop: "4px",
                display: "block",
              }}
            >
              🇪🇸 España: 9 dígitos (ej: 612345678) - el +34 se agrega
              automáticamente
              <br />
              🌍 Otros países: +[código][número] (ej: +1234567890)
            </small>
          </div>

          {smsSent && (
            <div className="form-group">
              <label htmlFor="sms-code">Código SMS (6 dígitos):</label>
              <input
                id="sms-code"
                type="text"
                placeholder="000000"
                value={smsCode}
                onChange={(e) =>
                  setSmsCode(e.target.value.replace(/\D/g, "").slice(0, 6))
                }
                maxLength="6"
                required
              />
            </div>
          )}

          <button type="submit" disabled={loading} className="btn-primary">
            {loading
              ? "Cargando..."
              : smsSent
                ? "Verificar Código"
                : "Enviar Código SMS"}
          </button>
        </form>
      )}

      {/* Botones de inicio de sesión social */}
      {!isRegistering && !isSmsLogin && (
        <div className="social-auth-buttons">
          <button
            onClick={handleGoogleSignIn}
            disabled={loading}
            className="btn-google"
            title="Inicia sesión con tu cuenta Google"
          >
            🔐 Google
          </button>
          <button
            onClick={handleGitHubSignIn}
            disabled={loading}
            className="btn-github"
            title="Inicia sesión con tu cuenta GitHub"
          >
            💻 GitHub
          </button>
        </div>
      )}

      <button
        onClick={() => {
          setIsRegistering(!isRegistering);
          setError(null);
          setEmail("");
          setPassword("");
          setName("");
          setPhone("");
          setSmsCode("");
          setSmsSent(false);
          setIsSmsLogin(false);
        }}
        className="btn-secondary"
      >
        {isRegistering
          ? "¿Ya tienes cuenta? Inicia sesión"
          : "¿No tienes cuenta? Regístrate"}
      </button>

      {/* Botón para cambiar entre login normal y SMS */}
      {!isRegistering && (
        <button
          onClick={() => {
            setIsSmsLogin(!isSmsLogin);
            setError(null);
            setEmail("");
            setPassword("");
            setPhone("");
            setSmsCode("");
            setSmsSent(false);
          }}
          className="btn-sms"
        >
          {isSmsLogin ? "📧 Usar Email/Contraseña" : "📱 Usar SMS"}
        </button>
      )}

      {error && (
        <div
          className={
            error.includes("Por favor") ? "success-message" : "error-message"
          }
        >
          {error}
        </div>
      )}
    </div>
  );
};

export default Login;
